//! Spec-compliance tests: Section and Header/Footer Behavioral Constraints
//! (ISO 29500-1 sections 17.6.22, 17.10.2, 17.10.5, 17.10.6)
//!
//! These tests verify behavioral constraints around section properties:
//! - Header/footer inheritance across sections
//! - titlePg interaction with first-page headers
//! - Continuous section property inheritance
//!
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/create_section_constraints.py`.

use stemma::{BlockNode, CanonDoc, HeaderFooterKind, InlineNode, TrackedBlock};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/section-constraints";

// -- helpers ----------------------------------------------------------------

/// Extract plain text from tracked blocks.
fn blocks_text(blocks: &[TrackedBlock]) -> String {
    let mut text = String::new();
    for tb in blocks {
        if let BlockNode::Paragraph(p) = &tb.block {
            for inline in p.all_inlines() {
                if let InlineNode::Text(t) = inline {
                    text.push_str(&t.text);
                }
            }
        }
    }
    text
}

/// Collect all mid-document section properties (from pPr/sectPr).
fn section_paragraphs(doc: &CanonDoc) -> Vec<&stemma::SectionProperties> {
    let mut props = Vec::new();
    collect_section_props_tracked(&doc.blocks, &mut props);
    props
}

fn collect_section_props_tracked<'a>(
    blocks: &'a [TrackedBlock],
    out: &mut Vec<&'a stemma::SectionProperties>,
) {
    for tracked in blocks {
        match &tracked.block {
            BlockNode::Paragraph(p) => {
                if let Some(ref sp) = p.section_properties {
                    out.push(sp);
                }
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_section_props_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

fn collect_section_props_bare<'a>(
    blocks: &'a [BlockNode],
    out: &mut Vec<&'a stemma::SectionProperties>,
) {
    for block in blocks {
        match block {
            BlockNode::Paragraph(p) => {
                if let Some(ref sp) = p.section_properties {
                    out.push(sp);
                }
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_section_props_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

// ==========================================================================
// HEADER INHERITANCE (ISO 29500-1 sections 17.10.2 / 17.10.5)
// ==========================================================================

/// ISO 29500-1 sections 17.10.2 / 17.10.5: Header inheritance across sections.
///
/// Section 1 defines a default header "Section 1 Header". Section 2 does
/// NOT define a header reference. Per spec, Section 2 should inherit the
/// header from Section 1.
///
/// This test verifies the fixture loads correctly and that the document
/// has exactly one header story (the one defined by Section 1). Whether
/// the model computes inheritance for Section 2 is tested separately.
#[test]
fn spec_section_has_header_from_section_1() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "header-inheritance");

    // The document should have at least one header (the one from Section 1)
    assert!(
        !doc.headers.is_empty(),
        "document should have at least one header story"
    );

    // Verify the header contains "Section 1 Header"
    let default_hdr = doc
        .headers
        .iter()
        .find(|h| h.kind == HeaderFooterKind::Default);
    assert!(
        default_hdr.is_some(),
        "should have a Default-kind header, got kinds: {:?}",
        doc.headers.iter().map(|h| &h.kind).collect::<Vec<_>>()
    );

    let text = blocks_text(&default_hdr.unwrap().blocks);
    assert!(
        text.contains("Section 1 Header"),
        "Default header should contain 'Section 1 Header', got: '{text}'"
    );
}

/// ISO 29500-1 sections 17.10.2 / 17.10.5: Section 2 inherits header from Section 1.
///
/// When a section does not define its own headerReference, the spec says it
/// inherits the header from the previous section. The model resolves this
/// inheritance during import, populating `header_refs` on each section.
#[test]
fn spec_section_inherits_header_from_previous() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "header-inheritance");

    // Document has 2 sections, 1 header part.
    assert_eq!(doc.headers.len(), 1);
    let header_part = &doc.headers[0].part_name;

    // Section 1 (mid-document): declares the default header
    let all_paras = common::all_paragraphs(&doc);
    let sect1_para = all_paras
        .iter()
        .find(|p| p.section_properties.is_some())
        .expect("should find a paragraph with section_properties");
    let sect1_sp = sect1_para.section_properties.as_ref().unwrap();
    assert_eq!(sect1_sp.header_refs.len(), 1);
    assert_eq!(sect1_sp.header_refs[0].kind, HeaderFooterKind::Default);
    assert_eq!(&sect1_sp.header_refs[0].part_path, header_part);

    // Section 2 (body-level): inherits default header from Section 1
    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist");
    assert_eq!(body_sp.header_refs.len(), 1);
    assert_eq!(body_sp.header_refs[0].kind, HeaderFooterKind::Default);
    assert_eq!(
        &body_sp.header_refs[0].part_path, header_part,
        "Section 2 should inherit Section 1's default header"
    );
}

/// ISO 29500-1 §17.10.2: Per-kind header inheritance across 3 sections.
///
/// S1 declares default + first headers. S2 declares only first (overrides S1's
/// first, inherits S1's default). S3 declares nothing (inherits both from S2).
#[test]
fn spec_section_partial_header_inheritance() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "partial-header-inheritance");

    // 3 header parts in the document
    assert_eq!(doc.headers.len(), 3, "should have 3 header parts");

    let all_paras = common::all_paragraphs(&doc);
    let sect_paras: Vec<_> = all_paras
        .iter()
        .filter(|p| p.section_properties.is_some())
        .collect();
    assert_eq!(sect_paras.len(), 2, "should have 2 mid-document sections");

    let s1_sp = sect_paras[0].section_properties.as_ref().unwrap();
    let s2_sp = sect_paras[1].section_properties.as_ref().unwrap();
    let s3_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body section properties");

    // S1: 2 effective refs (default + first)
    assert_eq!(s1_sp.header_refs.len(), 2, "S1 should have 2 header refs");

    // S2: 2 effective refs (inherited default from S1 + own first)
    assert_eq!(
        s2_sp.header_refs.len(),
        2,
        "S2 should have 2 header refs (own first + inherited default)"
    );

    // S3: 2 effective refs (inherited from S2)
    assert_eq!(
        s3_sp.header_refs.len(),
        2,
        "S3 should have 2 header refs (both inherited)"
    );

    // S2's default part_path == S1's default part_path (inherited)
    let s1_default = s1_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Default)
        .unwrap();
    let s2_default = s2_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Default)
        .unwrap();
    assert_eq!(
        s1_default.part_path, s2_default.part_path,
        "S2 should inherit S1's default header"
    );

    // S2's first part_path != S1's first part_path (overridden)
    let s1_first = s1_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::First)
        .unwrap();
    let s2_first = s2_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::First)
        .unwrap();
    assert_ne!(
        s1_first.part_path, s2_first.part_path,
        "S2 should override S1's first header"
    );

    // S3 inherits exactly what S2 has
    let s3_default = s3_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Default)
        .unwrap();
    let s3_first = s3_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::First)
        .unwrap();
    assert_eq!(
        s3_default.part_path, s2_default.part_path,
        "S3 inherits default from S2"
    );
    assert_eq!(
        s3_first.part_path, s2_first.part_path,
        "S3 inherits first from S2"
    );
}

