// ==========================================================================
// TITLE PAGE INTERACTION (ISO 29500-1 sections 17.10.6 / 17.6.18)
// ==========================================================================

/// ISO 29500-1 sections 17.10.6 / 17.6.18: titlePg enables first-page header.
///
/// The fixture has titlePg=true in the body-level sectPr, with both a
/// default header ("Default Header") and a first-page header
/// ("First Page Header"). This test verifies the headers are parsed
/// and the titlePg flag is present.
#[test]
fn spec_title_page_enables_first_page_header() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "title-page-interaction");

    // Should have at least 2 headers: default + first
    assert!(
        doc.headers.len() >= 2,
        "should have at least 2 headers (default + first), got {}",
        doc.headers.len()
    );

    // Verify first-page header exists with correct content
    let first_hdr = doc
        .headers
        .iter()
        .find(|h| h.kind == HeaderFooterKind::First);
    assert!(
        first_hdr.is_some(),
        "should have a First-kind header, got kinds: {:?}",
        doc.headers.iter().map(|h| &h.kind).collect::<Vec<_>>()
    );
    let text = blocks_text(&first_hdr.unwrap().blocks);
    assert!(
        text.contains("First Page Header"),
        "First header should contain 'First Page Header', got: '{text}'"
    );

    // Verify default header exists with correct content
    let default_hdr = doc
        .headers
        .iter()
        .find(|h| h.kind == HeaderFooterKind::Default);
    assert!(
        default_hdr.is_some(),
        "should have a Default-kind header, got kinds: {:?}",
        doc.headers.iter().map(|h| &h.kind).collect::<Vec<_>>()
    );
    let text = blocks_text(&default_hdr.unwrap().blocks);
    assert!(
        text.contains("Default Header"),
        "Default header should contain 'Default Header', got: '{text}'"
    );

    // Verify titlePg flag is parsed in body_section_properties
    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should be Some -- body-level sectPr has titlePg");
    assert_eq!(
        body_sp.title_page,
        Some(true),
        "body_section_properties.title_page should be Some(true), got {:?}",
        body_sp.title_page
    );
}

