// ==========================================================================
// CONTINUOUS SECTION INHERITANCE (ISO 29500-1 sections 17.6.22)
// ==========================================================================

/// ISO 29500-1 sections 17.6.22: Continuous section inherits page properties.
///
/// Section 1 has explicit margins (top=1440, bottom=1440, left=1800,
/// right=1800). Section 2 is a continuous section break with NO margins
/// specified. Per spec, Section 2 should inherit Section 1's margins.
///
/// The import pipeline propagates page-level properties (margins, page size)
/// from the preceding section into continuous sections that omit them.
#[test]
fn spec_continuous_section_inherits_page_properties() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "continuous-section");

    // Section 1 is a mid-document sectPr with explicit margins
    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one mid-document section (Section 1)"
    );

    // Verify Section 1 has its explicit margins
    let s1 = section_props[0];
    assert_eq!(
        s1.margin_top,
        Some(1440),
        "Section 1 margin_top should be 1440, got {:?}",
        s1.margin_top
    );
    assert_eq!(
        s1.margin_left,
        Some(1800),
        "Section 1 margin_left should be 1800, got {:?}",
        s1.margin_left
    );

    // Section 2 is the body-level sectPr with continuous type
    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should be Some for the continuous section");

    assert_eq!(
        body_sp.section_type,
        Some(stemma::domain::SectionType::Continuous),
        "Section 2 should be continuous, got {:?}",
        body_sp.section_type
    );

    // Per spec, Section 2 (continuous) should inherit margins from Section 1
    // since it doesn't define its own.
    assert_eq!(
        body_sp.margin_top,
        Some(1440),
        "Section 2 (continuous) margin_top should inherit 1440 from Section 1, got {:?}",
        body_sp.margin_top
    );
    assert_eq!(
        body_sp.margin_left,
        Some(1800),
        "Section 2 (continuous) margin_left should inherit 1800 from Section 1, got {:?}",
        body_sp.margin_left
    );
    assert_eq!(
        body_sp.margin_bottom,
        Some(1440),
        "Section 2 (continuous) margin_bottom should inherit 1440 from Section 1, got {:?}",
        body_sp.margin_bottom
    );
    assert_eq!(
        body_sp.margin_right,
        Some(1800),
        "Section 2 (continuous) margin_right should inherit 1800 from Section 1, got {:?}",
        body_sp.margin_right
    );
}
